import{_ as a,o as r,c as o,a2 as n}from"./chunks/framework.BWuWLRhz.js";const m=JSON.parse('{"title":"Core Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts.md","filePath":"guide/concepts.md"}'),t={name:"guide/concepts.md"};function s(i,e,c,p,d,h){return r(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h1><p>Tragwerk organizes everything into a small set of nouns. From the top down: a <strong>Team</strong> owns <strong>Projects</strong>, each Project has per-branch <strong>Environments</strong>, and Environments run <strong>Applications</strong> backed by <strong>Services</strong> and exposed through <strong>Routes</strong> and <strong>Domains</strong>. <strong>Servers</strong> are the VPS targets you deploy to.</p><h2 id="teams-roles" tabindex="-1">Teams &amp; Roles <a class="header-anchor" href="#teams-roles" aria-label="Permalink to &quot;Teams &amp; Roles&quot;">​</a></h2><p>A Team is the top-level owner of everything in Tragwerk — projects, servers, and billing all belong to a team. Membership is governed by role-based access control with three roles: <strong>Owner</strong>, <strong>Admin</strong>, and <strong>Member</strong>. Owners and Admins manage members and settings; Members work within the projects they are granted access to. See <a href="/app/teams">Teams</a> and your personal <a href="/app/account">account settings</a>.</p><h2 id="projects" tabindex="-1">Projects <a class="header-anchor" href="#projects" aria-label="Permalink to &quot;Projects&quot;">​</a></h2><p>A Project maps to a single git repository and is the unit you configure and deploy. It holds the connection to your git provider, shared settings, and the set of environments created from your branches. See <a href="/app/projects">Projects</a> and <a href="/app/integrations">integrations</a> for connecting a repository.</p><h2 id="environments" tabindex="-1">Environments <a class="header-anchor" href="#environments" aria-label="Permalink to &quot;Environments&quot;">​</a></h2><p>An Environment is one running instance of your project, derived from a git branch — push a branch and you get an environment. Each environment is isolated, with its own containers, <a href="/app/services">services</a>, <a href="/app/variables">variables</a>, and <a href="/app/domains">domains</a>. This makes branches usable as staging or preview environments alongside production. See <a href="/app/environments">Environments</a>.</p><h2 id="servers" tabindex="-1">Servers <a class="header-anchor" href="#servers" aria-label="Permalink to &quot;Servers&quot;">​</a></h2><p>A Server is a VPS you register with Tragwerk as a deployment target. After you add a server, an automated setup job provisions it over SSH and turns it into a Docker host ready to run your apps. One server can host many applications and environments side by side. See <a href="/self-hosting/servers">Servers</a> and <a href="/self-hosting/server-setup">server setup</a>.</p><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>An Application is a PHP service defined in your <a href="/config/applications">config.xml</a> — its runtime (for example <code>php:8.5</code>), its source root, and its <a href="/config/web">web</a> configuration. Applications are served by FrankenPHP, which by default acts as a drop-in PHP-FPM replacement (classic mode) so existing apps run unchanged; adding <a href="/config/applications#workermode"><code>&lt;workerMode&gt;</code></a> opts in to worker mode for higher throughput. An environment can run one or more applications. Long-running tasks are handled by <a href="/app/workers">workers</a> and scheduled tasks by <a href="/app/cronjobs">cronjobs</a>.</p><h2 id="services" tabindex="-1">Services <a class="header-anchor" href="#services" aria-label="Permalink to &quot;Services&quot;">​</a></h2><p>A Service is a backing component such as a database or cache (PostgreSQL, MySQL, Redis, and others) declared in your config. Applications connect to services through <a href="/config/relationships">relationships</a>, which inject the connection details as environment variables at runtime. See <a href="/app/services">Services (app)</a> and <a href="/config/services">Services (config)</a>.</p><h2 id="routes-domains" tabindex="-1">Routes &amp; Domains <a class="header-anchor" href="#routes-domains" aria-label="Permalink to &quot;Routes &amp; Domains&quot;">​</a></h2><p>Routes map incoming URLs to your applications and are declared in the <a href="/config/routes">routes</a> section of your config. Traefik uses them to direct traffic and to terminate TLS. A Domain is a hostname you attach to an environment; Tragwerk obtains a Let&#39;s Encrypt certificate for it automatically. See <a href="/app/domains">Domains</a>.</p><h2 id="deployments" tabindex="-1">Deployments <a class="header-anchor" href="#deployments" aria-label="Permalink to &quot;Deployments&quot;">​</a></h2><p>A Deployment is one build-and-release cycle for an environment: Tragwerk clones the repository, builds the Docker image from your generated configuration, and starts the containers. Deployments are triggered by a git push (via webhook) or manually as a redeploy, and you can watch their progress in a live log. See <a href="/app/deployments">Deployments</a>.</p>',18)])])}const g=a(t,[["render",s]]);export{m as __pageData,g as default};
